import React from 'react'
import { Outlet, NavLink, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import {
  LayoutDashboard, Clock, Calendar, FileText, Users,
  BarChart2, LogOut, CheckSquare, List, KeyRound,
  ShieldCheck, ClipboardList
} from 'lucide-react'

const CB_LOGO = 'data:image/png;base64,'

export default function Shell({ children }: { children?: React.ReactNode }) {
  const { user: ctxUser, logout } = useAuth()
  const navigate = useNavigate()

  const stored = localStorage.getItem('user')
  const user = ctxUser || (stored ? JSON.parse(stored) : null)
  const isAdmin = user?.role === 'admin'
  const isSuperAdmin = user?.is_superadmin === true

  const handleLogout = async () => {
    await logout()
    navigate('/login')
  }

  // Employee: 5 tabs
  const employeeLinks = [
    { to: '/dashboard', icon: LayoutDashboard, label: 'Home' },
    { to: '/attendance', icon: Clock, label: 'Attendance' },
    { to: '/leave/apply', icon: Calendar, label: 'Apply' },
    { to: '/leave/history', icon: FileText, label: 'History' },
    { to: '/change-password', icon: KeyRound, label: 'Password' },
  ]

  // Admin: more tabs — shown in sidebar on desktop, scrollable bottom nav on mobile
  const adminLinks = [
    { to: '/admin', icon: LayoutDashboard, label: 'Home' },
    { to: '/admin/users', icon: Users, label: 'Staff' },
    { to: '/admin/attendance', icon: CheckSquare, label: 'Attendance' },
    { to: '/admin/daily-updates', icon: ClipboardList, label: 'Updates' },
    { to: '/admin/leave', icon: List, label: 'Leave' },
    { to: '/admin/reports', icon: BarChart2, label: 'Reports' },
    ...(isSuperAdmin ? [{ to: '/admin/audit', icon: ShieldCheck, label: 'Audit' }] : []),
    { to: '/change-password', icon: KeyRound, label: 'Password' },
  ]

  const links = isAdmin ? adminLinks : employeeLinks

  return (
    <div className="app-shell">

      {/* ── Desktop sidebar ── */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <img src={CB_LOGO} alt="CB Enterprises" style={{ width: 38, height: 'auto', objectFit: 'contain', flexShrink: 0 }} />
          <div className="sidebar-logo-text">
            <span>CB Enterprises</span>
            <small>{isSuperAdmin ? 'Super Admin' : isAdmin ? 'Sub Admin' : 'Staff Portal'}</small>
          </div>
        </div>
        <nav className="sidebar-nav">
          {links.map(({ to, icon: Icon, label }) => (
            <NavLink
              key={to}
              to={to}
              end={to === '/admin' || to === '/dashboard'}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
            >
              <Icon size={16} />
              {label}
            </NavLink>
          ))}
        </nav>
        <div className="sidebar-footer">
          <div className="sidebar-user">
            <strong>{user?.name}</strong>
            {user?.employee_id}
          </div>
          <button
            className="btn btn-sm"
            style={{ width: '100%', color: 'rgba(255,255,255,0.7)', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)' }}
            onClick={handleLogout}
          >
            <LogOut size={14} /> Sign out
          </button>
        </div>
      </aside>

      {/* ── Main content ── */}
      <main className="main-content">
        <div className="page">
          {children ?? <Outlet />}
        </div>
      </main>

      {/* ── Mobile bottom nav — ALL tabs, horizontally scrollable ── */}
      <nav className="mobile-nav">
        {links.map(({ to, icon: Icon, label }) => (
          <NavLink
            key={to}
            to={to}
            end={to === '/admin' || to === '/dashboard'}
            className={({ isActive }) => `mobile-nav-item ${isActive ? 'active' : ''}`}
          >
            <Icon size={20} />
            <span>{label}</span>
          </NavLink>
        ))}
      </nav>

    </div>
  )
}
